parts.content:
apiVersion: v1
data:
  default.conf.template: |
    server {
        listen 80;
        location = /healthz {
            return 200 "ok\n";
            access_log off;
        }
        location / {
            proxy_pass ${REQUIRED_API_BASE};
        }
    }
kind: ConfigMap
metadata:
  labels:
    kustomize.toolkit.fluxcd.io/name: flux-system
    kustomize.toolkit.fluxcd.io/namespace: flux-system
  name: vigil-app-nginx-config
  namespace: default

parts.args:
{"title":"fix(remediation): set REQUIRED_API_BASE env var in vigil-app Deployment","body":"Root cause: The REQUIRED_API_BASE environment variable is set to an empty string in the Deployment manifest, causing nginx's proxy_pass directive to fail with invalid syntax when envsubst processes the ConfigMap template.

Evidence: nginx: [emerg] invalid number of arguments in "proxy_pass" directive in /etc/nginx/conf.d/default.conf:8

Affected resources: Deployment/vigil-app, Pod/vigil-app-547945c74-ctt77"}
